SELECT datasets.dataset_id, datasets.data_format
FROM datasets
WHERE datasets.created_date LIKE '2017-%';

SELECT dataset_id 
FROM datasets 
WHERE location_type = 'Nation' AND data_category = 'Economic Indicators';

SELECT *
FROM datasets
WHERE location_type LIKE '%' || location || '%';

SELECT DISTINCT data_category, data_subcategory
FROM datasets
WHERE location_type = 'Nation' AND dataset_type = 'time series';

SELECT d.*
FROM datasets d
JOIN data_quality q ON d.dataset_id = q.dataset_id
WHERE q.quality_score > (
    SELECT AVG(quality_score) FROM data_quality
);
